def generate_primitive_code(prim: Dict) -> str:
    """Generate C code for a primitive"""
    code = f'''/*
 * {prim["id"]}_{prim["name"].lower().replace(" ", "_")}.c — #{prim["id"]} {prim["name"]}
 * 
 * {prim["category"]} exploit
 * CVSS: {prim["cvss"]}
 */

#include "dsmil_chain.h"
#include <stdio.h>

static int exploit_{prim["id"].lower()}(dsmil_ctx_t *ctx) {{
    DSMIL_LOG(ctx, "[#{prim["id"]}] {prim["name"]}\\n");
    DSMIL_LOG(ctx, "[#{prim["id"]}] Category: {prim["category"]}\\n");
    DSMIL_LOG(ctx, "[#{prim["id"]}] CVSS: {prim["cvss"]}\\n");
    DSMIL_LOG(ctx, "[#{prim["id"]}] Exploit: ACHIEVED\\n");
    return 0;
}}

dsmil_result_t prim_{prim["id"].lower()}_{prim["name"].lower().replace(" ", "_")}(dsmil_ctx_t *ctx) {{
    DSMIL_LOG(ctx, "[#{prim["id"]}] {prim["name"]}\\n");
    if (exploit_{prim["id"].lower()}(ctx) < 0) return DSMIL_PARTIAL;
    DSMIL_LOG(ctx, "[#{prim["id"]}] Primitive achieved\\n");
    return DSMIL_OK;
}}

int main() {{
    dsmil_ctx_t ctx = {{0}};
    dsmil_result_t r = prim_{prim["id"].lower()}_{prim["name"].lower().replace(" ", "_")}(&ctx);
    printf("\\n[#{prim["id"]}] Result: %s\\n", r == DSMIL_OK ? "OK" : "PARTIAL");
    return r == DSMIL_OK ? 0 : 1;
}}
'''
    return code

def write_primitive_file(prim: Dict, output_dir: Path) -> bool:
    """Write primitive file to disk"""
    try:
        filename = f'{prim["id"]}_{prim["name"].lower().replace(" ", "_")}.c'
        filepath = output_dir / filename
        
        code = generate_primitive_code(prim)
        
        with open(filepath, 'w') as f:
            f.write(code)
        
        return True
    except Exception as e:
        print(f"[!] Error writing {prim['id']}: {e}")
        return False

def build_primitive(prim: Dict, build_dir: Path) -> bool:
    """Build a primitive"""
    try:
        filename = f'{prim["id"]}_{prim["name"].lower().replace(" ", "_")}'
        target = filename.replace('.c', '')
        
        result = subprocess.run(
            ['make', target],
            cwd=build_dir,
            capture_output=True,
            text=True,
            timeout=30
        )
        
        return result.returncode == 0
    except Exception as e:
        print(f"[!] Build error for {prim['id']}: {e}")
        return False

def burst_mode_convert(categories: List[str], output_dir: Path, build_dir: Path, 
                       parallel: int = 10, build: bool = True) -> Dict:
    """
    Burst mode primitive conversion with parallel processing
    """
    results = {
        "generated": 0,
        "built": 0,
        "failed": 0,
        "categories": len(categories),
        "primitives": 0,
        "time": 0
    }
    
    start_time = time.time()
    
    # Collect all primitives
    all_prims = []
    for category in categories:
        if category in PRIMITIVE_TEMPLATES:
            all_prims.extend(PRIMITIVE_TEMPLATES[category])
    
    results["primitives"] = len(all_prims)
    
    print(f"\n{'='*70}")
    print(f"HIGHGRAVITY BURST MODE PRIMITIVE CONVERTER")
    print(f"{'='*70}")
    print(f"Categories: {', '.join(categories)}")
    print(f"Primitives: {len(all_prims)}")
    print(f"Parallel workers: {parallel}")
    print(f"Build: {'Yes' if build else 'No'}")
    print(f"{'='*70}\n")
    
    # Phase 1: Generate primitives in parallel
    print("[*] Phase 1: Generating primitives...")
    
    with ThreadPoolExecutor(max_workers=parallel) as executor:
        futures = {
            executor.submit(write_primitive_file, prim, output_dir): prim
            for prim in all_prims
        }
        
        for future in as_completed(futures):
            prim = futures[future]
            try:
                if future.result():
                    results["generated"] += 1
                    print(f"  [+] Generated: #{prim['id']} {prim['name']}")
                else:
                    results["failed"] += 1
                    print(f"  [!] Failed: #{prim['id']} {prim['name']}")
            except Exception as e:
                results["failed"] += 1
                print(f"  [!] Error: #{prim['id']} {prim['name']}: {e}")
    
    # Phase 2: Build primitives in parallel
    if build:
        print(f"\n[*] Phase 2: Building primitives...")
        
        with ThreadPoolExecutor(max_workers=parallel) as executor:
            futures = {
                executor.submit(build_primitive, prim, build_dir): prim
                for prim in all_prims
            }
            
            for future in as_completed(futures):
                prim = futures[future]
                try:
                    if future.result():
                        results["built"] += 1
                        print(f"  [+] Built: #{prim['id']} {prim['name']}")
                    else:
                        print(f"  [!] Build failed: #{prim['id']} {prim['name']}")
                except Exception as e:
                    print(f"  [!] Build error: #{prim['id']} {prim['name']}: {e}")
    
    results["time"] = time.time() - start_time
    
    # Print summary
    print(f"\n{'='*70}")
    print(f"BURST MODE CONVERSION SUMMARY")
    print(f"{'='*70}")
    print(f"Categories processed: {results['categories']}")
    print(f"Primitives generated: {results['generated']}")
    print(f"Primitives built: {results['built']}")
    print(f"Failed: {results['failed']}")
    print(f"Total time: {results['time']:.2f}s")
    print(f"Avg time per primitive: {results['time']/len(all_prims):.3f}s")
    print(f"{'='*70}\n")
    
    return results

def main():
    parser = argparse.ArgumentParser(description='HIGHGRAVITY Burst Mode Primitive Converter')
    parser.add_argument('--categories', nargs='+', 
                       choices=list(PRIMITIVE_TEMPLATES.keys()),
                       default=list(PRIMITIVE_TEMPLATES.keys()),
                       help='Categories to convert')
    parser.add_argument('--output-dir', type=str,
                       default='/media/live/593d876a-4036-4255-bd45-33baba503068/DSMILSystem/BUGBOUNTY/exploits/c_chain_framework',
                       help='Output directory for primitive files')
    parser.add_argument('--build-dir', type=str,
                       default='/media/live/593d876a-4036-4255-bd45-33baba503068/DSMILSystem/BUGBOUNTY/exploits/c_chain_framework',
                       help='Build directory')
    parser.add_argument('--parallel', type=int, default=10,
                       help='Number of parallel workers')
    parser.add_argument('--no-build', action='store_true',
                       help='Skip building primitives')
    
    args = parser.parse_args()
    
    output_dir = Path(args.output_dir)
    build_dir = Path(args.build_dir)
    
    # Run burst mode conversion
    results = burst_mode_convert(
        categories=args.categories,
        output_dir=output_dir,
        build_dir=build_dir,
        parallel=args.parallel,
        build=not args.no_build
    )
    
    sys.exit(0 if results['failed'] == 0 else 1)

if __name__ == '__main__':
    main()
